import React, { useState, useEffect } from 'react';
import { useApp } from '../../context/AppContext';
import { calcBMI, getBMICategory, calcWaterGoal, calcStepGoal } from '../../utils/helpers';

export default function ProfilePage() {
  const { state, dispatch } = useApp();
  const [form, setForm] = useState({
    name: '', email: '', age: '', height: '', weight: '', gender: 'male', goal: 'maintain',
  });
  const [saved, setSaved] = useState(false);
  const [editing, setEditing] = useState(false);

  useEffect(() => {
    if (state.profile) setForm({ ...form, ...state.profile });
  }, [state.profile]);

  const bmi = calcBMI(form.weight, form.height);
  const bmiCat = getBMICategory(bmi);
  const waterGoal = calcWaterGoal(+form.weight);

  const handleSave = (e) => {
    e.preventDefault();
    const profile = {
      name: form.name, email: form.email,
      age: +form.age, height: +form.height,
      weight: +form.weight, gender: form.gender,
      goal: form.goal,
    };
    dispatch({ type: 'SET_PROFILE', payload: profile });
    localStorage.setItem(`health_profile_${state.user?.email}`, JSON.stringify(profile));
    setSaved(true);
    setEditing(false);
    setTimeout(() => setSaved(false), 3000);
  };

  const GOALS = [
    { v: 'lose', l: '🏃 Giảm cân', color: '#ff7b35' },
    { v: 'maintain', l: '⚖️ Duy trì', color: '#00e5a0' },
    { v: 'gain', l: '💪 Tăng cơ', color: '#a855f7' },
  ];

  return (
    <div>
      <div style={styles.header}>
        <div>
          <div style={styles.title}>👤 Hồ sơ sức khỏe</div>
          <div style={styles.sub}>Quản lý thông tin cá nhân của bạn</div>
        </div>
        {saved && (
          <div style={styles.savedBadge}>✓ Đã lưu thành công</div>
        )}
      </div>

      <div style={styles.layout}>
        {/* Left: Avatar & summary */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          {/* Avatar card */}
          <div className="card" style={{ textAlign: 'center', padding: '32px 24px' }}>
            <div style={styles.avatar}>{(form.name || 'U')[0].toUpperCase()}</div>
            <div style={styles.profileName}>{form.name || 'Chưa đặt tên'}</div>
            <div style={styles.profileEmail}>{state.user?.email}</div>
            <div style={styles.profileMeta}>
              {form.age && <span>{form.age} tuổi</span>}
              {form.gender && <span>{form.gender === 'male' ? '♂ Nam' : '♀ Nữ'}</span>}
            </div>
            {form.goal && (
              <div style={{ ...styles.goalBadge, background: GOALS.find(g => g.v === form.goal)?.color + '18', color: GOALS.find(g => g.v === form.goal)?.color }}>
                {GOALS.find(g => g.v === form.goal)?.l}
              </div>
            )}
          </div>

          {/* Health summary */}
          <div className="card">
            <div style={styles.sectionTitle}>Chỉ số sức khỏe</div>
            {[
              { l: 'Chiều cao', v: form.height ? `${form.height} cm` : '--', i: '📏' },
              { l: 'Cân nặng', v: form.weight ? `${form.weight} kg` : '--', i: '⚖️' },
              { l: 'BMI', v: bmi || '--', i: '📊', sub: bmiCat?.label, color: bmiCat?.color },
              { l: 'Mục tiêu nước/ngày', v: form.weight ? `${waterGoal} ml` : '--', i: '💧', color: '#00e5a0' },
              { l: 'Mục tiêu bước/ngày', v: '10,000', i: '👟', color: '#00d4ff' },
            ].map(item => (
              <div key={item.l} style={styles.metaRow}>
                <span style={{ fontSize: 16 }}>{item.i}</span>
                <span style={{ flex: 1, fontSize: 13, color: '#8892aa' }}>{item.l}</span>
                <span style={{ fontFamily: 'var(--font-display)', fontWeight: 700, fontSize: 14, color: item.color || '#f0f4ff' }}>{item.v}</span>
                {item.sub && <span style={{ fontSize: 11, color: item.color, marginLeft: 4 }}>({item.sub})</span>}
              </div>
            ))}
          </div>
        </div>

        {/* Right: Edit form */}
        <div style={{ flex: 1 }}>
          <div className="card">
            <div style={styles.formHeader}>
              <div style={styles.sectionTitle}>Thông tin cá nhân</div>
              {!editing ? (
                <button className="btn btn-ghost btn-sm" onClick={() => setEditing(true)}>✏️ Chỉnh sửa</button>
              ) : (
                <button className="btn btn-ghost btn-sm" style={{ color: '#ff4f8b' }} onClick={() => setEditing(false)}>✕ Hủy</button>
              )}
            </div>

            <form onSubmit={handleSave} style={styles.form}>
              <div className="grid-2">
                <div className="input-group">
                  <label className="input-label">Họ và tên</label>
                  <input className="input-field" value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} disabled={!editing} placeholder="Nguyễn Văn A" />
                </div>
                <div className="input-group">
                  <label className="input-label">Tuổi</label>
                  <input type="number" className="input-field" value={form.age} onChange={e => setForm({ ...form, age: e.target.value })} disabled={!editing} placeholder="25" />
                </div>
              </div>

              <div className="grid-2">
                <div className="input-group">
                  <label className="input-label">Chiều cao (cm)</label>
                  <input type="number" className="input-field" value={form.height} onChange={e => setForm({ ...form, height: e.target.value })} disabled={!editing} placeholder="170" />
                </div>
                <div className="input-group">
                  <label className="input-label">Cân nặng (kg)</label>
                  <input type="number" step="0.1" className="input-field" value={form.weight} onChange={e => setForm({ ...form, weight: e.target.value })} disabled={!editing} placeholder="65" />
                </div>
              </div>

              <div className="input-group">
                <label className="input-label">Giới tính</label>
                <div style={styles.genderGroup}>
                  {[{ v: 'male', l: '♂ Nam' }, { v: 'female', l: '♀ Nữ' }].map(g => (
                    <button
                      key={g.v} type="button"
                      disabled={!editing}
                      onClick={() => editing && setForm({ ...form, gender: g.v })}
                      style={{
                        ...styles.genderBtn,
                        ...(form.gender === g.v ? styles.genderBtnActive : {}),
                        opacity: !editing ? 0.6 : 1,
                        cursor: !editing ? 'default' : 'pointer',
                      }}
                    >
                      {g.l}
                    </button>
                  ))}
                </div>
              </div>

              <div className="input-group">
                <label className="input-label">Mục tiêu sức khỏe</label>
                <div style={styles.goalGroup}>
                  {GOALS.map(g => (
                    <button
                      key={g.v} type="button"
                      disabled={!editing}
                      onClick={() => editing && setForm({ ...form, goal: g.v })}
                      style={{
                        ...styles.goalBtn,
                        ...(form.goal === g.v ? { background: g.color + '18', border: `1px solid ${g.color}40`, color: g.color } : {}),
                        opacity: !editing ? 0.6 : 1,
                        cursor: !editing ? 'default' : 'pointer',
                      }}
                    >
                      {g.l}
                    </button>
                  ))}
                </div>
              </div>

              {editing && (
                <button type="submit" className="btn btn-primary" style={{ width: '100%', marginTop: 8 }}>
                  💾 Lưu thay đổi
                </button>
              )}
            </form>
          </div>

          {/* BMI meter */}
          {bmi && (
            <div className="card" style={{ marginTop: 16 }}>
              <div style={styles.sectionTitle}>Chỉ số BMI của bạn</div>
              <div style={styles.bmiMeter}>
                <div style={styles.bmiBar}>
                  {[
                    { from: 0, to: 25, color: '#00d4ff' },
                    { from: 25, to: 50, color: '#00e5a0' },
                    { from: 50, to: 75, color: '#ff7b35' },
                    { from: 75, to: 100, color: '#ff4f8b' },
                  ].map(s => (
                    <div key={s.from} style={{ ...styles.bmiSegment, background: s.color, opacity: 0.6 }} />
                  ))}
                  {/* Marker */}
                  <div style={{
                    ...styles.bmiMarker,
                    left: `${Math.min(95, Math.max(5, (parseFloat(bmi) - 14) / (35 - 14) * 100))}%`,
                    background: bmiCat?.color,
                  }} />
                </div>
                <div style={styles.bmiLabels}>
                  <span>14</span><span>18.5</span><span>23</span><span>27.5</span><span>35</span>
                </div>
              </div>
              <div style={{ textAlign: 'center', marginTop: 12 }}>
                <span style={{ fontFamily: 'var(--font-display)', fontSize: 28, fontWeight: 800, color: bmiCat?.color }}>{bmi}</span>
                <span style={{ fontSize: 14, color: '#8892aa', marginLeft: 8 }}>{bmiCat?.label}</span>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

const styles = {
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 28 },
  title: { fontFamily: 'var(--font-display)', fontSize: 28, fontWeight: 800, color: '#f0f4ff', marginBottom: 4 },
  sub: { fontSize: 14, color: '#8892aa' },
  savedBadge: {
    background: 'rgba(0,229,160,0.12)', border: '1px solid rgba(0,229,160,0.3)',
    borderRadius: 20, padding: '8px 16px',
    fontFamily: 'var(--font-display)', fontWeight: 700, fontSize: 13, color: '#00e5a0',
    animation: 'fadeInUp 0.3s ease',
  },
  layout: { display: 'flex', gap: 20, flexWrap: 'wrap', alignItems: 'flex-start' },
  avatar: {
    width: 72, height: 72,
    background: 'linear-gradient(135deg, #00d4ff, #a855f7)',
    borderRadius: '50%',
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    fontFamily: 'var(--font-display)', fontWeight: 800, fontSize: 28, color: '#000',
    margin: '0 auto 16px',
    boxShadow: '0 8px 24px rgba(0,212,255,0.25)',
  },
  profileName: { fontFamily: 'var(--font-display)', fontWeight: 800, fontSize: 18, color: '#f0f4ff', marginBottom: 4 },
  profileEmail: { fontSize: 13, color: '#8892aa', marginBottom: 12 },
  profileMeta: { display: 'flex', gap: 12, justifyContent: 'center', fontSize: 13, color: '#4a5568', marginBottom: 12 },
  goalBadge: { display: 'inline-flex', padding: '6px 16px', borderRadius: 20, fontFamily: 'var(--font-display)', fontWeight: 700, fontSize: 13, marginTop: 8 },
  sectionTitle: { fontFamily: 'var(--font-display)', fontWeight: 700, fontSize: 15, color: '#f0f4ff', marginBottom: 16 },
  metaRow: { display: 'flex', alignItems: 'center', gap: 10, padding: '8px 0', borderBottom: '1px solid rgba(255,255,255,0.04)' },
  formHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 },
  form: { display: 'flex', flexDirection: 'column', gap: 16 },
  genderGroup: { display: 'flex', gap: 10 },
  genderBtn: { flex: 1, padding: '10px', borderRadius: 10, background: 'var(--bg-secondary)', border: '1px solid rgba(255,255,255,0.06)', color: '#8892aa', fontFamily: 'var(--font-display)', fontWeight: 600, fontSize: 13, transition: 'all 0.2s ease' },
  genderBtnActive: { background: 'rgba(0,212,255,0.1)', border: '1px solid #00d4ff', color: '#00d4ff' },
  goalGroup: { display: 'flex', gap: 10 },
  goalBtn: { flex: 1, padding: '10px', borderRadius: 10, background: 'var(--bg-secondary)', border: '1px solid rgba(255,255,255,0.06)', color: '#8892aa', fontFamily: 'var(--font-display)', fontWeight: 600, fontSize: 12, transition: 'all 0.2s ease' },
  bmiMeter: { position: 'relative' },
  bmiBar: { position: 'relative', height: 16, borderRadius: 8, overflow: 'visible', display: 'flex', marginBottom: 6 },
  bmiSegment: { flex: 1, height: '100%' },
  bmiMarker: { position: 'absolute', top: '50%', transform: 'translate(-50%, -50%)', width: 20, height: 20, borderRadius: '50%', border: '3px solid #fff', transition: 'left 0.6s ease', boxShadow: '0 0 10px rgba(0,0,0,0.4)', zIndex: 2 },
  bmiLabels: { display: 'flex', justifyContent: 'space-between', fontSize: 10, color: '#4a5568' },
};
